arguments.command:
python /app/decompress.py /tmp/nout; echo "decompress rc=$?"
python3 -c "
import os,filecmp
def snap(root):
    d={}
    for dp,dn,fn in os.walk(root):
        for f in fn:
            p=os.path.join(dp,f); d[os.path.relpath(p,root)]=open(p,'rb').read()
    return d
a=snap('/tmp/nin'); b=snap('/tmp/nout')
print('nin files:',len(a),'nout files:',len(b))
print('IDENTICAL' if a==b else ('DIFF keys %s'%(set(a)^set(b))))
"

